Sinif aşağıdakı sintaksislə təyin edilir:
class ClassName {
public:
  data_type member1;
  return_type function();
private:
  data_type member2;
};
- **ClassName**: Sinifin adı.
- **member1, member2**: Sinifin üzvləri (dəyişənlər).
- **function**: Sinifin üzv funksiyası (metod).
- **public/private**: Giriş səviyyələri, hansı üzvlərin xaricdən əlçatan olduğunu müəyyənləşdirir.

content.code:
#include <iostream>
#include <string>

class Person {
public:
  std::string name;
  int age;
  void printInfo() {
    std::cout << "Name: " << name << std::endl;
    std::cout << "Age: " << age << std::endl;
  }
private:
  double salary;
};

int main() {
  Person person;
  person.name = "Ali";
  person.age = 25;
  person.printInfo();
  return 0;
}
// Output:
// Name: Ali
// Age: 25

#include <iostream>
#include <string>

class Person {
public:
  std::string name;
  int age;
  Person(std::string n, int a) : name(n), age(a) {}
  ~Person() {
    std::cout << "Object destroyed" << std::endl;
  }
  void printInfo() {
    std::cout << "Name: " << name << std::endl;
    std::cout << "Age: " << age << std::endl;
  }
};

int main() {
  Person person("Veli", 30);
  person.printInfo();
  return 0;
}
// Output:
// Name: Veli
// Age: 30
// Object destroyed

#include <iostream>
#include <string>

class Person {
public:
  std::string name;
  int age;
  Person(std::string n, int a) : name(n), age(a) {}
  void printInfo() {
    std::cout << "Name: " << name << std::endl;
    std::cout << "Age: " << age << std::endl;
  }
};

int main() {
  Person* ptr = new Person("Ayşe", 28);
  ptr->printInfo();
  delete ptr;
  return 0;
}
// Output:
// Name: Ayşe
// Age: 28

